import{_ as s,o as a,c as t,a2 as e}from"./chunks/framework.BqADHfKx.js";const c=JSON.parse('{"title":"为什么选择 Qore","description":"Qore 是围绕流式响应设计的前端 runtime","frontmatter":{"title":"为什么选择 Qore","description":"Qore 是围绕流式响应设计的前端 runtime","keywords":["Qore","流式响应","Signal","Streaming","TypeScript"]},"headers":[],"relativePath":"zh/guide/why-qore.md","filePath":"zh/guide/why-qore.md","lastUpdated":null}'),h={name:"zh/guide/why-qore.md"};function n(r,i,l,d,p,k){return a(),t("div",null,[...i[0]||(i[0]=[e(`<h1 id="为什么选择-qore" tabindex="-1">为什么选择 Qore <a class="header-anchor" href="#为什么选择-qore" aria-label="Permalink to &quot;为什么选择 Qore&quot;">​</a></h1><p>Qore 不是“又一个前端框架”。它围绕一个问题设计：<strong>AI 与实时应用的数据不是快照，而是一条持续变化的流。</strong></p><h2 id="一个核心-primitive" tabindex="-1">一个核心 primitive <a class="header-anchor" href="#一个核心-primitive" aria-label="Permalink to &quot;一个核心 primitive&quot;">​</a></h2><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">const </span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">answer</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> =</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> stream</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(</span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">openAI</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">.</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">chat</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">hello</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">))</span></span></code></pre></div><p><code>answer</code> 是一个 <code>QoreStream</code>，同时也是只读 signal。</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">answer</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">()</span><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;">        // 当前累积内容</span></span>
<span class="line"><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">answer</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">.</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">status</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">()</span><span style="--shiki-light:#A0ADA0;--shiki-dark:#758575DD;"> // runtime 状态</span></span></code></pre></div><p>UI 只需要声明依赖：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">return</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> h</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">div</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">,</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> {},</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> text</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(()</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> =&gt;</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> answer</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">()))</span></span></code></pre></div><p>当 token 到达，Qore 更新 signal；当 signal 更新，Qore 只刷新依赖它的 text node。</p><h2 id="为什么这很重要" tabindex="-1">为什么这很重要 <a class="header-anchor" href="#为什么这很重要" aria-label="Permalink to &quot;为什么这很重要&quot;">​</a></h2><p>React、Vue、Solid 都能处理 stream，但 stream 通常是“额外接进来的东西”。Qore 的选择是把 stream 放进 runtime 中心：</p><table tabindex="0"><thead><tr><th>问题</th><th>常见做法</th><th>Qore</th></tr></thead><tbody><tr><td>token 累积</td><td>手动拼字符串</td><td><code>stream()</code> 自动 reduce</td></tr><tr><td>UI 更新</td><td>组件级状态更新</td><td>text node 级响应</td></tr><tr><td>provider 差异</td><td>每个 provider 单独适配</td><td>async iterable + <code>stream()</code></td></tr><tr><td>高频 token</td><td>应用自己节流</td><td>backpressure primitive</td></tr></tbody></table><h2 id="适合场景" tabindex="-1">适合场景 <a class="header-anchor" href="#适合场景" aria-label="Permalink to &quot;适合场景&quot;">​</a></h2><ul><li>AI 聊天、Copilot、Agent 工作台</li><li>实时日志、任务进度、SSE 数据流</li><li>Markdown / code streaming preview</li><li>需要细粒度更新的轻量 UI</li></ul><h2 id="设计边界" tabindex="-1">设计边界 <a class="header-anchor" href="#设计边界" aria-label="Permalink to &quot;设计边界&quot;">​</a></h2><p>Qore 核心包不追求自带 Button、Dialog、Tabs。它应该保持小而硬：signal、stream、DOM binding、provider adapters。</p><p>官网、示例和组件实验可以在单独仓库或 experimental 区域演进；核心 runtime 只服务流式响应。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/zh/guide/quick-start.html">5 分钟快速入门</a></li><li><a href="/zh/guide/streaming.html">流式响应指南</a></li><li><a href="/zh/api/streaming.html">Streaming API</a></li></ul>`,19)])])}const g=s(h,[["render",n]]);export{c as __pageData,g as default};
